def gen(rng, size):
    n = max(1, min(size, 100000))
    candies = [rng.randint(1, 10000000) for _ in range(n)]
    if rng.randint(0, 1) == 0:
        k = rng.randint(1, sum(candies) + 10)
    else:
        k = rng.randint(1, 1000000000000)
    return [candies, k]

