class Solution:
    def maximumCandies(self, candies, k):
        lo, hi = 1, max(candies)
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            total = 0
            for c in candies:
                total += c // mid
                if total >= k:
                    break
            if total >= k:
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

