var maximumCandies = function(candies, k) {
    let lo = 1, hi = Math.max(...candies);
    let ans = 0;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        let total = 0;
        for (const c of candies) {
            total += Math.floor(c / mid);
            if (total >= k) break;
        }
        if (total >= k) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
};
